import React, { useEffect, useState } from "react";
import axios from "axios";
import { Container, Card, CardContent, Typography, Button, Grid, TextField, AppBar, Toolbar } from "@mui/material";

const Menu = () => {
  const [menuItems, setMenuItems] = useState([]);
  const [newItem, setNewItem] = useState({
    name: "",
    description: "",
    price: "",
    category: "",
  });

  useEffect(() => {
    axios
      .get("http://localhost:8000/menu")
      .then((response) => {
        setMenuItems(response.data);
      })
      .catch((error) => {
        console.error("There was an error fetching the menu!", error);
      });
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewItem({
      ...newItem,
      [name]: value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    axios
      .post("http://localhost:8000/menu", newItem)
      .then((response) => {
        setMenuItems([...menuItems, response.data]);
        setNewItem({ name: "", description: "", price: "", category: "" });
      })
      .catch((error) => {
        console.error("There was an error adding the menu item!", error);
      });
  };

  return (
    <div>
      {/* AppBar Header */}
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6">QuickBite</Typography>
        </Toolbar>
      </AppBar>

      {/* Main Content */}
      <Container sx={{ marginTop: 4 }}>
        <Typography variant="h3" gutterBottom align="center">
          Menu
        </Typography>

        {/* Add Menu Item Form */}
        <form onSubmit={handleSubmit} style={{ marginBottom: "20px" }}>
          <Grid container spacing={2} style={{ marginBottom: "20px" }}>
            <Grid item xs={12} sm={6}>
              <TextField
                label="Name"
                variant="outlined"
                fullWidth
                name="name"
                value={newItem.name}
                onChange={handleChange}
                required
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <TextField
                label="Description"
                variant="outlined"
                fullWidth
                name="description"
                value={newItem.description}
                onChange={handleChange}
                required
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <TextField
                label="Price"
                variant="outlined"
                fullWidth
                name="price"
                value={newItem.price}
                onChange={handleChange}
                required
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <TextField
                label="Category"
                variant="outlined"
                fullWidth
                name="category"
                value={newItem.category}
                onChange={handleChange}
                required
              />
            </Grid>
            <Grid item xs={12}>
              <Button type="submit" variant="contained" color="primary" fullWidth>
                Add Item
              </Button>
            </Grid>
          </Grid>
        </form>

        {/* Display Menu Items */}
        <Grid container spacing={3}>
          {menuItems.length === 0 ? (
            <Typography variant="h5" color="textSecondary" align="center" sx={{ width: "100%" }}>
              No menu items available.
            </Typography>
          ) : (
            menuItems.map((item) => (
              <Grid item xs={12} sm={6} md={4} key={item._id}>
                <Card sx={{ maxWidth: 345 }}>
                  <CardContent>
                    <Typography variant="h5" component="div">
                      {item.name}
                    </Typography>
                    <Typography variant="body2" color="text.secondary" sx={{ marginTop: 1 }}>
                      {item.description}
                    </Typography>
                    <Typography variant="h6" color="primary" sx={{ marginTop: 1 }}>
                      Price: ${item.price}
                    </Typography>
                    <Typography variant="body2" color="text.secondary" sx={{ marginTop: 1 }}>
                      Category: {item.category}
                    </Typography>
                  </CardContent>
                </Card>
              </Grid>
            ))
          )}
        </Grid>
      </Container>
    </div>
  );
};

export default Menu;
